"use client";

import { ArrowTurnBackwardIcon } from "@hugeicons/core-free-icons";
import type { IconSvgElement } from "@hugeicons/react";
import { HugeiconsIcon } from "@hugeicons/react";
import { motion } from "framer-motion";
import { useState } from "react";
import { cn } from "@/shared/lib/cn";
import { Button } from "@/shared/ui/button";
import { ConfirmDialog } from "@/shared/ui/confirm-dialog";

export interface SidebarLink {
	key: string;
	label: string;
	icon: IconSvgElement;
}

interface SettingsSidebarProps {
	links: SidebarLink[];
	activeKey: string;
	onSelect: (key: string) => void;
	onReset?: () => void;
}

export function SettingsSidebar({ links, activeKey, onSelect, onReset }: SettingsSidebarProps) {
	const [expanded, setExpanded] = useState(false);
	const [resetConfirmOpen, setResetConfirmOpen] = useState(false);

	return (
		<motion.nav
			animate={{ width: expanded ? 170 : 52 }}
			className="flex h-full shrink-0 flex-col overflow-hidden border-border border-r bg-surface-primary"
			initial={false}
			onMouseEnter={() => setExpanded(true)}
			onMouseLeave={() => setExpanded(false)}
			transition={{ duration: 0.2, ease: [0.25, 0.1, 0.25, 1] }}
		>
			<div className="flex flex-1 flex-col gap-1 p-3 px-2">
				{links.map((link) => {
					const isActive = link.key === activeKey;
					return (
						<SidebarItem
							expanded={expanded}
							icon={link.icon}
							isActive={isActive}
							key={link.key}
							label={link.label}
							onClick={() => onSelect(link.key)}
						/>
					);
				})}
			</div>
			{onReset && (
				<div className="p-2">
					<ConfirmDialog
						confirmLabel="Reset"
						description="All settings will be restored to their default values. This cannot be undone."
						onConfirm={onReset}
						onOpenChange={setResetConfirmOpen}
						open={resetConfirmOpen}
						title="Reset to Defaults?"
					/>
					<Button
						className="w-full justify-start rounded-md bg-transparent p-0 transition-colors duration-150 hover:bg-surface-tertiary"
						onClick={() => setResetConfirmOpen(true)}
						title="Reset to Defaults"
					>
						<span className="flex items-center">
							<span className="flex w-9 shrink-0 items-center justify-center">
								<HugeiconsIcon
									className="text-foreground-muted"
									icon={ArrowTurnBackwardIcon}
									size={16}
								/>
							</span>
							<motion.span
								animate={{
									opacity: expanded ? 1 : 0,
									display: expanded ? "inline" : "none",
								}}
								className="whitespace-nowrap font-sans text-foreground-secondary text-xs"
								transition={{ duration: 0.15, delay: expanded ? 0.05 : 0 }}
							>
								Reset Defaults
							</motion.span>
						</span>
					</Button>
				</div>
			)}
		</motion.nav>
	);
}

function SidebarItem({
	icon,
	label,
	isActive,
	expanded,
	onClick,
}: {
	icon: IconSvgElement;
	label: string;
	isActive: boolean;
	expanded: boolean;
	onClick: () => void;
}) {
	return (
		<div className="relative">
			{isActive && (
				<motion.div
					className="absolute top-1 bottom-1 left-0 z-10 w-[3px] rounded-r-sm bg-accent"
					layoutId="sidebar-indicator"
					transition={{ duration: 0.2, ease: [0.25, 0.1, 0.25, 1] }}
				/>
			)}
			<Button
				className={cn(
					"h-9 w-full justify-start rounded-md p-0 transition-colors duration-150",
					isActive ? "bg-surface-elevated" : "bg-transparent hover:bg-surface-tertiary"
				)}
				onClick={onClick}
			>
				<span className="flex items-center">
					<span className="flex w-9 shrink-0 items-center justify-center">
						<HugeiconsIcon
							className={cn(
								"transition-colors duration-150",
								isActive ? "text-accent" : "text-foreground-muted"
							)}
							icon={icon}
							size={16}
						/>
					</span>
					<motion.span
						animate={{
							opacity: expanded ? 1 : 0,
							display: expanded ? "inline" : "none",
						}}
						className={cn(
							"whitespace-nowrap font-sans text-[13px]",
							isActive ? "font-medium text-foreground" : "text-foreground-secondary"
						)}
						transition={{ duration: 0.15, delay: expanded ? 0.05 : 0 }}
					>
						{label}
					</motion.span>
				</span>
			</Button>
		</div>
	);
}
