"use client";

import { Dialog } from "@base-ui/react/dialog";
import {
	AiBrainIcon,
	Configuration01Icon,
	KeyboardIcon,
	Mic01Icon,
	Note01Icon,
	SlidersHorizontalIcon,
	TextIcon,
} from "@hugeicons/core-free-icons";
import { useState } from "react";
import { useSettingsStore } from "@/features/update-settings";
import { dialogAnimation } from "@/shared/ui/dialog-animation";
import { AudioSettingsPanel } from "@/widgets/audio-settings";
import { DictionarySettingsPanel } from "@/widgets/dictionary-settings";
import { GeneralSettingsPanel } from "@/widgets/general-settings";
import { HotkeySettingsPanel } from "@/widgets/hotkey-settings";
import { ModelSettingsPanel } from "@/widgets/model-settings";
import { QualitySettingsPanel } from "@/widgets/quality-settings";
import { SnippetsSettingsPanel } from "@/widgets/snippets-settings";
import { SettingsSidebar, type SidebarLink } from "./SettingsSidebar";

const LINKS: SidebarLink[] = [
	{ key: "general", label: "General", icon: Configuration01Icon },
	{ key: "model", label: "Model", icon: AiBrainIcon },
	{ key: "audio", label: "Audio", icon: Mic01Icon },
	{ key: "quality", label: "Processing", icon: SlidersHorizontalIcon },
	{ key: "hotkey", label: "Hotkey", icon: KeyboardIcon },
	{ key: "dictionary", label: "Dictionary", icon: TextIcon },
	{ key: "snippets", label: "Snippets", icon: Note01Icon },
];

const PANELS: Record<string, React.FC> = {
	model: ModelSettingsPanel,
	quality: QualitySettingsPanel,
	audio: AudioSettingsPanel,
	hotkey: HotkeySettingsPanel,
	dictionary: DictionarySettingsPanel,
	snippets: SnippetsSettingsPanel,
	general: GeneralSettingsPanel,
};

interface SettingsDialogProps {
	isOpen: boolean;
	onClose: () => void;
}

export function SettingsDialog({ isOpen, onClose }: SettingsDialogProps) {
	const [activeSection, setActiveSection] = useState("general");
	const resetSettings = useSettingsStore((s) => s.resetSettings);
	const Panel = PANELS[activeSection] ?? GeneralSettingsPanel;

	return (
		<Dialog.Root
			onOpenChange={(open) => {
				if (!open) {
					onClose();
				}
			}}
			open={isOpen}
		>
			<Dialog.Portal>
				<Dialog.Backdrop
					className={`${dialogAnimation.backdrop} fixed inset-0 z-[100] bg-black/60 backdrop-blur-sm`}
				/>
				<Dialog.Popup
					className={`${dialogAnimation.popup} fixed top-1/2 left-1/2 z-[101] overflow-hidden rounded-xl border border-border bg-surface-secondary outline-none`}
				>
					<div className="flex h-[520px] w-[640px]">
						<SettingsSidebar
							activeKey={activeSection}
							links={LINKS}
							onReset={resetSettings}
							onSelect={setActiveSection}
						/>
						<div className="flex-1 overflow-auto bg-surface p-4">
							<Panel />
						</div>
					</div>
				</Dialog.Popup>
			</Dialog.Portal>
		</Dialog.Root>
	);
}
